import React, { useContext, useState } from "react";
import { FormContext } from "../Contexts/FormContext";
import { EventCaller, ServerEventCaller } from "../BusinessLogics/EventHandler";


const NumericBox  = ({ eid, fieldname, cap, col, mn, ev, val, mxLen , rid}) => {
  
  const { register, formState: { errors } } = useContext(FormContext);
  const { setValue, getValues, eDefHldr, stageGridRefs, watch, trigger } = useContext(FormContext);

  
  
  const [formData, setFormData] = useState({});

  let clientevent = {}
  if (ev & ev != "") {
    clientevent = JSON.parse(ev.change);
  }


  /* store previous value to avoid event fire when tabout */
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prevState => ({ ...prevState, [name]: value }));
  };


  return (
    <div className={`${col} mb-3`}>
      <label
        htmlFor={fieldname}
        className={`${mn ? "required" : ""} form-label`}
      >
        {cap}
      </label>
      <input
        name={fieldname}
        type="number"
        className="form-control"
        disabled = {eDefHldr.stg.prp[fieldname].ro}
        {...register(fieldname, {
          required: mn,
          maxLength: { mxLen, message: " is required" },
          value: val=="" ? 0 : val ,
          onBlur: (e) => {
            if (clientevent.fn) {
              EventCaller(
                clientevent.fn,
                fieldname,
                clientevent.outel,
                getValues,
                setValue
              )
            }
            if (eDefHldr.stg.sev[fieldname]) {

              const currentValues = watch(fieldname);

              const previousValue = formData[fieldname];

              if (previousValue !== currentValues) {

                ServerEventCaller(
                  eDefHldr,
                  getValues(),
                  eDefHldr.stg.sev[fieldname].ev.change,
                  stageGridRefs,
                  setValue
                )
                handleChange(e)
              }
            }
          }
        })}
      />
    </div>
  );
};

export default NumericBox;
